# Validate plugin code against allowlist of safe patterns
sub validate_plugin_code {
    my ($code, $filename) = @_;

    if (length($code) > $MAX_CODE_LENGTH) {
        log_event('ERROR', "Plugin '$filename' exceeds maximum code length ($MAX_CODE_LENGTH bytes).");
        return 0;
    }

    if ($code =~ /[^[:print:]\s]/) {
