            return 0;
        }
    }

    return 1;
}

# Read plugin file safely
sub read_plugin_file {
    my ($filename) = @_;

    # Validate filename is in allowlist
    my $basename = basename($filename);
    unless (exists $ALLOWED_PLUGINS{$basename}) {
        log_event('ERROR', "Plugin '$basename' is not in the allowed plugins list.");
        return undef;
    }

    # Construct full path and canonicalize
    my $full_path = File::Spec->catfile($ALLOWED_PLUGIN_DIR, $basename);
    $full_path = File::Spec->canonpath($full_path);

    # Path traversal check
    my $canon_dir = File::Spec->canonpath($ALLOWED_PLUGIN_DIR);
    unless (index($full_path, $canon_dir) == 0) {
        log_event('ERROR', "Path traversal detected for plugin '$basename'.");
        return undef;
    }

    unless (-f $full_path && -r $full_path) {
        log_event('ERROR', "Plugin file '$full_path' does not exist or is not readable.");
        return undef;
    }

    # Check file ownership and permissions
    my @stat = stat($full_path);
    my $mode = $stat[2] & 07777;
    if ($mode & 0002) {
        log_event('ERROR', "Plugin file '$full_path' is world-writable. Refusing to load.");
        return undef;
    }

    # Read the file
    my $fh;
    unless (open($fh, '<', $full_path)) {
        log_event('ERROR', "Cannot open plugin file '$full_path': $!");
        return undef;
    }
    local $/;
    my $code = <$fh>;
    close($fh);

    # Untaint the code after validation
    if ($code =~ /^(.+)$/s) {
        $code = $1;
    }

    return $code;
}

# Execute plugin in a restricted compartment
sub execute_plugin {
    my ($plugin_name, %params) = @_;

    log_event('INFO', "Loading plugin: $plugin_name");

    my $code = read_plugin_file($plugin_name);
    unless (defined $code) {
        log_event('ERROR', "Failed to read plugin '$plugin_name'.");
        return undef;
    }

    # Validate the code
    unless (validate_plugin_code($code, $plugin_name)) {
        log_event('ERROR', "Plugin '$plugin_name' failed validation. Execution denied.");
        return undef;
    }

    log_event('INFO', "Executing plugin '$plugin_name' in Safe compartment.");

    # Use Safe module to create a restricted execution compartment
    require Safe;
    my $compartment = Safe->new();

    # Only permit a minimal set of opcodes
    $compartment->permit_only(qw(
        :base_core :base_mem :base_loop :base_orig :base_math
        padany lineseq leaveeval const rv2sv sassign padsv
        pushmark return leavesub entereval rv2av aelem rv2hv
        helem aassign concat join substr uc lc length
        print say stringify
        add subtract multiply divide modulo
        lt gt le ge eq ne cmp
        and or not
        preinc postinc predec postdec
        int abs hex oct
        sort reverse map grep
        push pop shift unshift splice
        chomp chop
        defined undef ref
        wantarray caller
        regcomp regcreset regcmaybe
        match subst trans
        enteriter iter entertry leavetry
    ));

    # Share parameters with the compartment via a hash
    my %plugin_params = %params;
    $compartment->share('%plugin_params');

    # Wrap the code to capture the return value
    my $wrapped_code = "no strict; no warnings; $code";

    my $result = $compartment->reval($wrapped_code);

    if ($@) {
        log_event('ERROR', "Plugin '$plugin_name' execution error: $@");
        return undef;
    }

    log_event('INFO', "Plugin '$plugin_name' executed successfully.");
    return $result;
}

